import{_ as n,o as i,c as a,ai as h}from"./chunks/framework.CJDL-GS7.js";const u=JSON.parse('{"title":"Giới thiệu TunAcademy","description":"","frontmatter":{},"headers":[],"relativePath":"general-introduction.md","filePath":"general-introduction.md","lastUpdated":null}'),o={name:"general-introduction.md"};function r(e,t,c,l,d,s){return i(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="gioi-thieu-tunacademy" tabindex="-1">Giới thiệu TunAcademy <a class="header-anchor" href="#gioi-thieu-tunacademy" aria-label="Permalink to &quot;Giới thiệu TunAcademy&quot;">​</a></h1><p>TunAcademy là nền tảng học tập trực tuyến K-12 dành riêng cho học sinh từ lớp 1 đến lớp 12. Hệ thống cung cấp kho bài học, bài tập và đề thi trực tuyến — học mọi lúc, mọi nơi, hoàn toàn miễn phí.</p><h2 id="cac-tinh-nang-chinh" tabindex="-1">Các tính năng chính <a class="header-anchor" href="#cac-tinh-nang-chinh" aria-label="Permalink to &quot;Các tính năng chính&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tính năng</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Bài học</strong></td><td>Kho 500+ bài học theo chương trình K-12, phân loại theo môn và lớp</td></tr><tr><td><strong>Bài tập</strong></td><td>Hệ thống bài tập tự luyện từ cơ bản đến nâng cao, chấm điểm tự động</td></tr><tr><td><strong>Đề thi</strong></td><td>Thi trực tuyến có giới hạn thời gian, kết quả và đáp án chi tiết</td></tr><tr><td><strong>Lớp học</strong></td><td>Lớp học ảo kết nối học sinh — giáo viên, quản lý bài vở và điểm số</td></tr><tr><td><strong>Học trực tuyến</strong></td><td>Phòng học livestream giữa giáo viên và học sinh theo thời gian thực</td></tr></tbody></table><h2 id="ba-vai-tro-tren-tunacademy" tabindex="-1">Ba vai trò trên TunAcademy <a class="header-anchor" href="#ba-vai-tro-tren-tunacademy" aria-label="Permalink to &quot;Ba vai trò trên TunAcademy&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Vai trò</th><th>Chức năng</th></tr></thead><tbody><tr><td>🎓 <strong>Học sinh</strong></td><td>Xem bài học, làm bài tập, tham gia kiểm tra, theo dõi tiến độ</td></tr><tr><td>👨‍🏫 <strong>Giáo viên</strong></td><td>Quản lý bài học, giao bài, tạo đề thi, chấm điểm, mở lớp trực tuyến</td></tr><tr><td>⚙️ <strong>Quản trị viên</strong></td><td>Quản lý toàn bộ hệ thống: người dùng, lớp học, môn học, năm học</td></tr></tbody></table><h2 id="bat-đau-nhanh-theo-vai-tro" tabindex="-1">Bắt đầu nhanh theo vai trò <a class="header-anchor" href="#bat-đau-nhanh-theo-vai-tro" aria-label="Permalink to &quot;Bắt đầu nhanh theo vai trò&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Học sinh mới</p><ol><li><a href="/register-login">Đăng ký tài khoản</a> → Chọn vai trò <strong>Học sinh</strong></li><li>Đợi giáo viên/admin thêm vào lớp học</li><li>Vào <strong>Dashboard → Lớp học</strong> để xem bài được giao</li><li>Đọc <a href="/student-guide">Hướng dẫn Học sinh</a> để làm quen</li></ol></div><div class="tip custom-block"><p class="custom-block-title">Giáo viên mới</p><ol><li>Liên hệ quản trị viên để được cấp tài khoản giáo viên</li><li>Đăng nhập → Vào <strong>Dashboard → Lớp chủ nhiệm</strong></li><li>Đọc <a href="/teacher-guide">Hướng dẫn Giáo viên</a> để bắt đầu</li></ol></div><div class="tip custom-block"><p class="custom-block-title">Quản trị viên</p><ol><li>Đăng nhập bằng tài khoản admin</li><li>Vào <strong>Quản lý người dùng</strong> để tạo tài khoản giáo viên và học sinh</li><li>Đọc <a href="/admin-guide">Hướng dẫn Quản trị viên</a></li></ol></div><h2 id="yeu-cau-he-thong" tabindex="-1">Yêu cầu hệ thống <a class="header-anchor" href="#yeu-cau-he-thong" aria-label="Permalink to &quot;Yêu cầu hệ thống&quot;">​</a></h2><ul><li><strong>Trình duyệt:</strong> Chrome, Edge, Firefox, Safari phiên bản mới nhất</li><li><strong>Kết nối:</strong> Internet ổn định (tối thiểu 5 Mbps cho tính năng Live)</li><li><strong>Thiết bị:</strong> Máy tính, laptop, tablet hoặc điện thoại</li></ul>',12)])])}const m=n(o,[["render",r]]);export{u as __pageData,m as default};
